  1→import { useQuery } from "@tanstack/react-query";
  2→import { BookOpen, FolderKanban, Users } from "lucide-react";
  3→import { useMemo, useState } from "react";
  4→import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
  5→import { DatePicker } from "@/components/analytics/DatePicker";
  6→import { MultiSelect } from "@/components/analytics/MultiSelect";
  7→import { PageHeader } from "@/components/analytics/PageHeader";
  8→import { StatCard } from "@/components/analytics/StatCard";
  9→import { LearningsTrendChart } from "@/components/charts/LearningsTrendChart";
 10→import { useDateRange } from "@/contexts/DateRangeContext";
 11→import { orpc } from "@/lib/orpc";
 12→
 13→export function LearningsPage() {
 14→	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
 15→		useDateRange();
 16→	const days = calculateDays();
 17→
 18→	const [splitBy, setSplitBy] = useState<"user_id" | "repository">("user_id");
 19→	const [selectedUsers, setSelectedUsers] = useState<string[]>([]);
 20→	const [selectedProjects, setSelectedProjects] = useState<string[]>([]);
 21→
 22→	const { data: learnings, isLoading } = useQuery(
 23→		orpc.analytics.learnings.list.queryOptions({
 24→			input: { days, limit: 100, offset: 0 },
 25→		}),
 26→	);
 27→
 28→	const { data: stats } = useQuery(
 29→		orpc.analytics.learnings.stats.queryOptions({ input: { days } }),
 30→	);
 31→
 32→	const { data: trendData } = useQuery(
 33→		orpc.analytics.learnings.trend.queryOptions({
 34→			input: { days, splitBy },
 35→		}),
 36→	);
 37→
 38→	const { data: availableUsers } = useQuery(
 39→		orpc.analytics.learnings.users.queryOptions({}),
 40→	);
 41→
 42→	const { data: availableProjects } = useQuery(
 43→		orpc.analytics.learnings.projects.queryOptions({}),
 44→	);
 45→
 46→	const { data: userMappings } = useQuery(
 47→		orpc.analytics.users.mappings.queryOptions({ input: { days: 30 } }),
 48→	);
 49→
 50→	const userMap = useMemo(() => {
 51→		const map = new Map<string, string>();
 52→		if (userMappings) {
 53→			for (const m of userMappings) {
 54→				map.set(m.user_id, m.username);
 55→			}
 56→		}
 57→		return map;
 58→	}, [userMappings]);
 59→
 60→	const userDisplayOptions = useMemo(() => {
 61→		if (!availableUsers) return [];
 62→		return availableUsers.map(
 63→			(userId) => userMap.get(userId) || `${userId.substring(0, 8)}...`,
 64→		);
 65→	}, [availableUsers, userMap]);
 66→
 67→	const projectDisplayOptions = useMemo(() => {
 68→		if (!availableProjects) return [];
 69→		return availableProjects.map((path) => {
 70→			const name = path.split("/").pop() || path;
 71→			return name;
 72→		});
 73→	}, [availableProjects]);
 74→
 75→	const filteredLearnings = useMemo(() => {
 76→		if (!learnings) return [];
 77→		return learnings.filter((learning) => {
 78→			if (
 79→				selectedUsers.length > 0 &&
 80→				!selectedUsers.includes(learning.user_id)
 81→			) {
 82→				return false;
 83→			}
 84→			if (
 85→				selectedProjects.length > 0 &&
 86→				!selectedProjects.includes(learning.project_path)
 87→			) {
 88→				return false;
 89→			}
 90→			return true;
 91→		});
 92→	}, [learnings, selectedUsers, selectedProjects]);
 93→
 94→	const handleUserFilterChange = (selectedNames: string[]) => {
 95→		if (!availableUsers) return;
 96→		const userIds = selectedNames.map((name) => {
 97→			const userId = availableUsers.find(
 98→				(id) => (userMap.get(id) || `${id.substring(0, 8)}...`) === name,
 99→			);
100→			return userId || name;
101→		});
102→		setSelectedUsers(userIds);
103→	};
104→
105→	const handleProjectFilterChange = (selected: string[]) => {
106→		if (!availableProjects) return;
107→		const fullPaths = selected.map((name) => {
108→			const path = availableProjects.find((p) => p.split("/").pop() === name);
109→			return path || name;
110→		});
111→		setSelectedProjects(fullPaths);
112→	};
113→
114→	return (
115→		<div className="px-8 py-6">
116→			<PageHeader
117→				title="Learning Feed"
118→				description="Team feedback and insights from /compound:feedback sessions"
119→				actions={
120→					<DatePicker
121→						startDate={startDate}
122→						endDate={endDate}
123→						onStartDateChange={setStartDate}
124→						onEndDateChange={setEndDate}
125→					/>
126→				}
127→			/>
128→
129→			{/* Stats Overview */}
130→			{stats && !isLoading && (
131→				<div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
132→					<StatCard
133→						title="Total Learnings"
134→						value={stats.total_learnings.toString()}
135→						icon={BookOpen}
136→						subtitle={`${stats.learnings_by_day.length} days with feedback`}
137→					/>
138→					<StatCard
139→						title="Team Members"
140→						value={stats.unique_users.toString()}
141→						icon={Users}
142→						subtitle="Contributing feedback"
143→					/>
144→					<StatCard
145→						title="Projects"
146→						value={stats.unique_projects.toString()}
147→						icon={FolderKanban}
148→						subtitle="With learnings captured"
149→					/>
150→				</div>
151→			)}
152→
153→			{/* Filters */}
154→			<div className="mb-6 flex flex-wrap gap-4">
155→				<MultiSelect
156→					options={userDisplayOptions}
157→					selected={selectedUsers.map(
158→						(userId) => userMap.get(userId) || `${userId.substring(0, 8)}...`,
159→					)}
160→					onChange={handleUserFilterChange}
161→					placeholder="All Users"
162→					className="w-64"
163→				/>
164→				<MultiSelect
165→					options={projectDisplayOptions}
166→					selected={selectedProjects.map((path) => {
167→						const name = path.split("/").pop() || path;
168→						return name;
169→					})}
170→					onChange={handleProjectFilterChange}
171→					placeholder="All Projects"
172→					className="w-64"
173→				/>
174→				{(selectedUsers.length > 0 || selectedProjects.length > 0) && (
175→					<button
176→						type="button"
177→						onClick={() => {
178→							setSelectedUsers([]);
179→							setSelectedProjects([]);
180→						}}
181→						className="px-4 py-2 text-sm text-muted hover:text-foreground hover:bg-hover rounded-md transition-colors"
182→					>
183→						Clear filters
184→					</button>
185→				)}
186→			</div>
187→
188→			{/* Learnings Trend Chart */}
189→			{trendData && trendData.length > 0 && !isLoading && (
190→				<AnalyticsCard className="mb-6">
191→					<h2 className="text-xl font-bold text-heading mb-4">
192→						Learnings Over Time
193→					</h2>
194→					<p className="text-sm text-muted mb-6">
195→						Feedback activity over time split by developer
196→					</p>
197→					<LearningsTrendChart
198→						data={trendData}
199→						splitBy={splitBy}
200→						onSplitByChange={setSplitBy}
201→						userMap={userMap}
202→					/>
203→				</AnalyticsCard>
204→			)}
205→
206→			{/* Timeline */}
207→			<AnalyticsCard>
208→				<div className="p-6">
209→					{filteredLearnings.length > 0 && (
210→						<div className="flex items-center justify-end mb-6">
211→							<span className="text-sm text-muted">
212→								{filteredLearnings.length}{" "}
213→								{filteredLearnings.length === 1 ? "learning" : "learnings"}
214→							</span>
215→						</div>
216→					)}
217→
218→					<p>Timeline coming soon</p>
219→				</div>
220→			</AnalyticsCard>
221→		</div>
222→	);
223→}
