 15→
 16→interface TimelineItemProps {
 17→	learning: LearningEntry;
 18→	userMap?: Record<string, string>;
 19→}
 20→
 21→export function TimelineItem({ learning, userMap }: TimelineItemProps) {
 22→	const [isExpanded, setIsExpanded] = useState(false);
 23→
 24→	// Format date
 25→	const formattedDate = format(new Date(learning.created_at), "MMM dd, yyyy");
 26→	const formattedTime = format(new Date(learning.created_at), "h:mm a");
 27→
 28→	// Truncate text for preview
 29→	const contentPreview =
 30→		learning.content.length > 300
 31→			? `${learning.content.slice(0, 300)}...`
 32→			: learning.content;
 33→
 34→	// Extract project name from path
 35→	const projectName =
 36→		learning.project_path.split("/").pop() || learning.project_path;
 37→
 38→	// Link to session
 39→	const sessionLink = `/dashboard/sessions/${learning.session_id}`;
 40→
 41→	// Get type badge color (decorative per-type, keep hardcoded)
 42→	const getTypeBadgeColor = (type: string) => {
 43→		switch (type) {
 44→			case "pattern":
 45→				return "bg-green-100 text-green-700 dark:bg-green-900 dark:text-green-300";
 46→			case "antipattern":
 47→				return "bg-red-100 text-red-700 dark:bg-red-900 dark:text-red-300";
 48→			case "convention":
 49→				return "bg-blue-100 text-blue-700 dark:bg-blue-900 dark:text-blue-300";
 50→			case "fix":
 51→				return "bg-yellow-100 text-yellow-700 dark:bg-yellow-900 dark:text-yellow-300";
 52→			case "preference":
 53→				return "bg-purple-100 text-purple-700 dark:bg-purple-900 dark:text-purple-300";
 54→			default:
 55→				return "bg-muted text-muted-foreground";
 56→		}
 57→	};
 58→
 59→	return (
 60→		<div className="relative pl-8 pb-8 border-l-2 border-border last:pb-0">
 61→			{/* Timeline dot */}
 62→			<div className="absolute -left-2 top-0 w-4 h-4 rounded-full bg-blue-600 border-2 border-background shadow" />
 63→
 64→			{/* Timestamp badge */}
 65→			<div className="flex items-center gap-2 mb-2 text-xs text-muted-foreground">
 66→				<Clock className="w-3 h-3" />
 67→				<span>
 68→					{formattedDate} at {formattedTime}
 69→				</span>
 70→			</div>
 71→
 72→			{/* Learning card */}
 73→			<div className="bg-card border border-border rounded-lg shadow-sm hover:shadow-md transition-shadow">
 74→				{/* Header */}
 75→				<div className="p-4 border-b border-border">
 76→					<div className="flex items-start justify-between gap-4">
 77→						<div className="flex-1 space-y-2">
 78→							{/* Type and Scope badges */}
 79→							<div className="flex flex-wrap items-center gap-2">
 80→								<span
 81→									className={cn(
 82→										"px-2 py-1 text-xs font-medium rounded",
 83→										getTypeBadgeColor(learning.type),
 84→									)}
 85→								>
 86→									{learning.type}
 87→								</span>
 88→								<span className="px-2 py-1 text-xs bg-muted text-muted-foreground rounded font-mono">
 89→									{learning.scope}
 90→								</span>
 91→							</div>
 92→
 93→							{/* Metadata */}
 94→							<div className="flex flex-wrap items-center gap-3 text-xs text-muted-foreground">
 95→								<div className="flex items-center gap-1">
 96→									<User className="w-3 h-3" />
 97→									<span className="font-medium">
 98→										{formatUsername(learning.user_id, userMap)}
 99→									</span>
100→								</div>
101→								<div className="flex items-center gap-1">
102→									<FolderKanban className="w-3 h-3" />
103→									<span className="font-mono">{projectName}</span>
104→								</div>
105→								{learning.repository && (
106→									<span className="px-2 py-0.5 bg-muted rounded text-muted-foreground">
107→										{learning.repository}
108→									</span>
109→								)}
110→							</div>
111→
112→							{/* Tags */}
113→							{learning.tags && learning.tags.length > 0 && (
114→								<div className="flex flex-wrap gap-1">
115→									{learning.tags.map((tag, idx) => (
116→										<span
117→											// biome-ignore lint/suspicious/noArrayIndexKey: tags may duplicate
118→											key={`${tag}-${idx}`}
119→											className="px-2 py-0.5 text-xs bg-indigo-100 text-indigo-700 dark:bg-indigo-900 dark:text-indigo-300 rounded"
120→										>
121→											#{tag}
122→										</span>
123→									))}
124→								</div>
125→							)}
126→						</div>
127→
128→						{/* Link to session */}
129→						<Link
130→							to={sessionLink}
131→							className="flex items-center gap-1 px-3 py-1.5 text-sm text-blue-600 dark:text-blue-400 hover:text-blue-700 dark:hover:text-blue-300 hover:bg-blue-50 dark:hover:bg-blue-950 rounded-md transition-colors"
132→						>
133→							<span>View Session</span>
134→							<ExternalLink className="w-3 h-3" />
135→						</Link>
136→					</div>
137→				</div>
138→
139→				{/* Learning content */}
140→				<div className="p-4">
141→					<div className="text-sm text-foreground leading-relaxed whitespace-pre-wrap">
142→						{isExpanded ? learning.content : contentPreview}
143→					</div>
144→
145→					{/* Expand/collapse button */}
146→					{learning.content.length > 300 && (
147→						<button
148→							type="button"
149→							onClick={() => setIsExpanded(!isExpanded)}
150→							className="flex items-center gap-1 text-sm text-blue-600 dark:text-blue-400 hover:text-blue-700 dark:hover:text-blue-300 font-medium mt-3"
151→						>
152→							{isExpanded ? (
153→								<>
154→									<ChevronUp className="w-4 h-4" />
155→									Show less
156→								</>
157→							) : (
158→								<>
159→									<ChevronDown className="w-4 h-4" />
160→									Show more
161→								</>
162→							)}
163→						</button>
164→					)}
165→				</div>
166→			</div>
167→		</div>
168→	);
169→}
