 41→	const [isCumulative, setIsCumulative] = useState(true);
 42→
 43→	const seriesKeys = useMemo(() => {
 44→		if (data.length === 0) return [];
 45→		const keys = new Set<string>();
 46→		for (const item of data) {
 47→			for (const key of Object.keys(item)) {
 48→				if (key !== "date") {
 49→					keys.add(key);
 50→				}
 51→			}
 52→		}
 53→		return Array.from(keys).sort();
 54→	}, [data]);
 55→
 56→	const chartData = useMemo(() => {
 57→		if (!isCumulative) {
 58→			return data.map((item) => ({
 59→				...item,
 60→				displayDate: new Date(item.date as string).toLocaleDateString("en-US", {
 61→					month: "short",
 62→					day: "numeric",
 63→				}),
 64→			}));
 65→		}
 66→
 67→		const cumulativeData = [];
 68→		const runningTotals: Record<string, number> = {};
 69→
 70→		for (const key of seriesKeys) {
 71→			runningTotals[key] = 0;
 72→		}
 73→
 74→		for (const item of data) {
 75→			const cumulativeItem: Record<string, unknown> = {
 76→				date: item.date,
 77→				displayDate: new Date(item.date as string).toLocaleDateString("en-US", {
 78→					month: "short",
 79→					day: "numeric",
 80→				}),
 81→			};
 82→
 83→			for (const key of seriesKeys) {
 84→				runningTotals[key] += (item[key] as number) || 0;
 85→				cumulativeItem[key] = runningTotals[key];
 86→			}
 87→
 88→			cumulativeData.push(cumulativeItem);
 89→		}
 90→
 91→		return cumulativeData;
 92→	}, [data, isCumulative, seriesKeys]);
 93→
 94→	const getDisplayName = (key: string): string => {
 95→		if (splitBy === "user_id" && userMap) {
 96→			return userMap.get(key) || `${key.substring(0, 12)}...`;
 97→		}
 98→		return key;
 99→	};
100→
101→	return (
102→		<div className="space-y-4">
