117→				<div className="flex items-center gap-2">
118→					<label
119→						htmlFor="cumulative-toggle"
120→						className="text-sm font-medium text-muted cursor-pointer"
121→					>
122→						Cumulative
123→					</label>
124→					<button
125→						type="button"
126→						id="cumulative-toggle"
127→						role="switch"
128→						aria-checked={isCumulative}
129→						onClick={() => setIsCumulative(!isCumulative)}
130→						className={`
131→							relative inline-flex h-6 w-11 items-center rounded-full transition-colors
132→							${isCumulative ? "bg-accent" : "bg-border"}
133→						`}
134→					>
135→						<span
