137→								inline-block h-4 w-4 transform rounded-full bg-input transition-transform
138→								${isCumulative ? "translate-x-6" : "translate-x-1"}
139→							`}
140→						/>
141→					</button>
142→				</div>
143→			</div>
144→
145→			<ResponsiveContainer width="100%" height={400}>
146→				<AreaChart
147→					data={chartData}
