 25→function getCliParams(): { cliCallback: string; state: string } | null {
 26→	const params = new URLSearchParams(window.location.search);
 27→	const cliCallback = params.get("cli_callback");
 28→	const state = params.get("state");
 29→	if (!cliCallback || !state) return null;
 30→	try {
 31→		const url = new URL(cliCallback);
 32→		if (url.hostname !== "127.0.0.1") return null;
 33→	} catch {
 34→		return null;
 35→	}
 36→	return { cliCallback, state };
 37→}
 38→
 39→function App() {
 40→	const { data: session, isPending } = authClient.useSession();
 41→	const [page, setPage] = useState<Page>("login");
 42→	const [cliRedirecting, setCliRedirecting] = useState(false);
 43→	const cliParams = getCliParams();
 44→	const { resolvedTheme } = useTheme();
 45→	const logoSrc =
 46→		resolvedTheme === "dark" ? "/logo-light.svg" : "/logo-dark.svg";
 47→
 48→	useEffect(() => {
 49→		if (!session || !cliParams || cliRedirecting) return;
 50→		setCliRedirecting(true);
 51→
 52→		fetch("/api/cli-token", { credentials: "include" })
 53→			.then((res) => res.json())
 54→			.then((data: { token: string }) => {
 55→				const redirectUrl = `${cliParams.cliCallback}?token=${encodeURIComponent(data.token)}&state=${encodeURIComponent(cliParams.state)}`;
 56→				window.location.href = redirectUrl;
 57→			});
 58→	}, [session, cliParams, cliRedirecting]);
 59→
 60→	if (isPending) {
 61→		return (
 62→			<div className="flex min-h-screen items-center justify-center">
 63→				<p className="text-muted-foreground">Loading...</p>
 64→			</div>
 65→		);
 66→	}
 67→
 68→	if (cliRedirecting) {
 69→		return (
 70→			<div className="flex min-h-screen items-center justify-center">
 71→				<p className="text-muted-foreground">Completing CLI login...</p>
 72→			</div>
 73→		);
 74→	}
 75→
 76→	if (!session) {
 77→		return (
 78→			<div className="flex min-h-screen flex-col items-center justify-center gap-6">
 79→				<img src={logoSrc} alt="Rudel" className="h-10 w-10" />
 80→				{page === "login" ? (
 81→					<LoginForm onSwitchToSignup={() => setPage("signup")} />
 82→				) : (
 83→					<SignupForm onSwitchToLogin={() => setPage("login")} />
 84→				)}
 85→			</div>
 86→		);
 87→	}
 88→
 89→	return (
 90→		<Routes>
 91→			<Route path="/" element={<Navigate to="/dashboard" replace />} />
 92→			<Route
 93→				path="/invitation/:invitationId"
 94→				element={<AcceptInvitationPage />}
 95→			/>
 96→			<Route path="/dashboard" element={<DashboardLayout />}>
 97→				<Route index element={<OverviewPage />} />
 98→				<Route path="developers" element={<DevelopersListPage />} />
 99→				<Route path="developers/:userId" element={<DeveloperDetailPage />} />
100→				<Route path="projects" element={<ProjectsListPage />} />
101→				<Route path="projects/:projectPath" element={<ProjectDetailPage />} />
102→				<Route path="sessions" element={<SessionsListPage />} />
103→				<Route path="sessions/:sessionId" element={<SessionDetailPage />} />
104→				<Route path="roi" element={<ROIPage />} />
105→				<Route path="errors" element={<ErrorsPage />} />
106→				<Route path="learnings" element={<LearningsPage />} />
107→				<Route path="profile" element={<ProfilePage />} />
108→				<Route path="organization" element={<OrganizationPage />} />
109→				<Route path="organization/new" element={<CreateOrgPage />} />
110→			</Route>
111→			<Route path="*" element={<Navigate to="/dashboard" replace />} />
