103→/**
104→ * Get learnings feed statistics
105→ */
106→export async function getLearningsFeedStats(
107→	orgId: string,
108→	params: {
109→		days?: number;
110→		user_id?: string;
111→		project_path?: string;
112→	} = {},
113→): Promise<LearningsFeedStats> {
114→	const { days = 30, user_id, project_path } = params;
115→	const org = escapeString(orgId);
116→	const d = Number(days);
117→
118→	let filters = `last_interaction_date >= now64(3) - INTERVAL ${d} DAY
119→    AND has(slash_commands, 'compound:feedback')
120→    AND organization_id = '${org}'`;
121→
122→	if (user_id) {
123→		filters += `\n    AND user_id = '${escapeString(user_id)}'`;
124→	}
125→	if (project_path) {
126→		filters += `\n    AND project_path = '${escapeString(project_path)}'`;
127→	}
128→
129→	const statsQuery = `
130→    SELECT
131→      count() as total_learnings,
132→      uniq(user_id) as unique_users,
133→      uniq(project_path) as unique_projects
134→    FROM rudel.session_analytics
135→    WHERE ${filters}
136→  `;
137→
138→	const timeSeriesQuery = `
139→    SELECT
140→      toDate(last_interaction_date) as date,
141→      count() as count
142→    FROM rudel.session_analytics
143→    WHERE ${filters}
144→    GROUP BY date
145→    ORDER BY date DESC
146→  `;
147→
148→	const [statsData, timeSeriesData] = await Promise.all([
149→		queryClickhouse<{
150→			total_learnings: number;
151→			unique_users: number;
152→			unique_projects: number;
153→		}>(statsQuery),
154→		queryClickhouse<{ date: string; count: number }>(timeSeriesQuery),
155→	]);
156→
157→	const stats = statsData[0] || {
158→		total_learnings: 0,
159→		unique_users: 0,
160→		unique_projects: 0,
161→	};
162→
163→	return {
164→		...stats,
165→		learnings_by_day: timeSeriesData,
166→	};
167→}
